1	const PROCESSING_FEE = 5;
2	const INITIAL_ASSESSMENT_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Scenario = {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	};
10	type QuoteResult = { premium: number };
11	type ScenarioResult = { results: QuoteResult[] };
12	
13	const BASE_PREMIUM: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	const BLOCK_OF_THREE_PREMIUM = 60;
24	
25	const priceComponentGroup = (type: string, count: number): number =>
26	  count === 3 ? BLOCK_OF_THREE_PREMIUM : count * BASE_PREMIUM[type];
27	
28	const sumBasePremiums = (items: Item[]): number => {
29	  const componentCounts = new Map<string, number>();
30	  let total = 0;
31	  for (const item of items) {
32	    if (COMPONENT_TYPES.has(item.type)) {
33	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
34	    } else {
35	      total += BASE_PREMIUM[item.type];
36	    }
37	  }
38	  for (const [type, count] of componentCounts) {
39	    total += priceComponentGroup(type, count);
40	  }
41	  return total;
42	};
43	
44	const quotePremium = (items: Item[]): number => {
45	  const base = sumBasePremiums(items);
46	  const surcharge = base * INITIAL_ASSESSMENT_SURCHARGE_RATE;
47	  return Math.ceil(base + surcharge) + PROCESSING_FEE;
48	};
49	
50	export const runScenario = (input: Scenario): ScenarioResult => {
51	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
52	  return { results };
53	};
